{
  "mode": "method",
  "tests": [
    {
      "name": "add_platform_success",
      "input": {
        "platform_name": "Instagram"
      },
      "output": {
        "status": "success",
        "message": "Platform added successfully."
      },
      "notes": "Validates the ability to add a new platform."
    },
    {
      "name": "delete_format_not_found",
      "input": {
        "format_id": "non_existing_format"
      },
      "output": {
        "status": "error",
        "message": "Format not found."
      },
      "notes": "Tests deletion of a format that does not exist."
    },
    {
      "name": "edit_platform_invalid_data",
      "input": {
        "platform_id": "valid_platform_id",
        "platform_name": ""
      },
      "output": {
        "status": "error",
        "message": "Invalid platform name."
      },
      "notes": "Checks handling of invalid data when editing a platform."
    },
    {
      "name": "set_default_aspect_ratio_success",
      "input": {
        "format_id": "valid_format_id",
        "aspect_ratio": "16:9"
      },
      "output": {
        "status": "success",
        "message": "Aspect ratio set successfully."
      },
      "notes": "Validates setting a default aspect ratio for a format."
    },
    {
      "name": "define_cropping_logic_success",
      "input": {
        "format_id": "valid_format_id",
        "cropping_logic": "face-centric"
      },
      "output": {
        "status": "success",
        "message": "Cropping logic defined successfully."
      },
      "notes": "Tests defining cropping logic for a format."
    },
    {
      "name": "enable_manual_editing_success",
      "input": {
        "platform_id": "valid_platform_id",
        "enable": true
      },
      "output": {
        "status": "success",
        "message": "Manual editing enabled."
      },
      "notes": "Validates enabling manual editing options for users."
    },
    {
      "name": "add_resizing_format_duplicate",
      "input": {
        "format_name": "Square",
        "platform_id": "valid_platform_id"
      },
      "output": {
        "status": "error",
        "message": "Resizing format already exists."
      },
      "notes": "Tests adding a resizing format that already exists."
    },
    {
      "name": "adaptation_strategy_invalid",
      "input": {
        "platform_id": "valid_platform_id",
        "strategy": "invalid_strategy"
      },
      "output": {
        "status": "error",
        "message": "Invalid adaptation strategy."
      },
      "notes": "Checks handling of invalid adaptation strategies."
    }
  ],
  "assumptions": "All IDs used in tests are valid and exist in the database.",
  "notes": "Tests cover both successful operations and edge cases."
}
